from pathlib import Path
import json

def load_config(path: str) -> dict:
    return json.loads(Path(path).read_text(encoding="utf-8"))

config = load_config("settings.json")
print(config.get("app_name", "demo"))

from dataclasses import dataclass

@dataclass
class Employee:
    name: str
    _salary: float

    @property
    def salary(self) -> float:
        return self._salary

    @salary.setter
    def salary(self, value: float) -> None:
        if value < 0:
            raise ValueError("salary cannot be negative")
        self._salary = value

    def give_raise(self, percent: float) -> None:
        self.salary = self.salary * (1 + percent / 100)

import pytest

def discount(price: float, percent: int) -> float:
    if percent < 0 or percent > 100:
        raise ValueError("invalid discount")
    return price * (1 - percent / 100)

@pytest.mark.parametrize(
    "price,percent,expected",
    [(100, 10, 90), (80, 25, 60), (50, 0, 50)],
)
def test_discount(price, percent, expected):
    assert discount(price, percent) == expected

from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

class Event(BaseModel):
    id: int
    title: str
    city: str

@app.get("/events/{event_id}", response_model=Event)
def get_event(event_id: int) -> Event:
    return Event(id=event_id, title="Python Meetup", city="Warsaw")
